import type { AnnotationsMarkerConfig } from '../../../types/annotations-marker-props.js';
import { AnnotationsMarkerGroup } from '../../../types/annotations.js';
import { AnnotationsTooltipItem } from '../types/annotations-tooltip-props.js';

interface TooltipHandlerData {
  hoveredMarkers: AnnotationsTooltipItem[];
  closeMarkers: AnnotationsTooltipItem[][];
}

/**
 * Builds a public tooltip item from a marker config by stripping the
 * internal-only fields (`id`, `priority`, `hidden`) and forwarding
 * everything else (including any user-supplied metadata) via `...rest`.
 */
const extractTooltipMarkerProps = (
  marker: AnnotationsMarkerConfig,
): AnnotationsTooltipItem => {
  const { id: _id, priority: _priority, hidden: _hidden, ...rest } = marker;

  return rest;
};

export const prepareCustomTooltipData = (
  data: AnnotationsMarkerGroup[],
  hoveredItemKey: string,
): TooltipHandlerData => {
  let hoveredMarkers: AnnotationsTooltipItem[] = [];
  const closeMarkers: AnnotationsTooltipItem[][] = [];

  data?.forEach((annotationGroup) => {
    const { key, markers } = annotationGroup;

    if (key === hoveredItemKey) {
      hoveredMarkers = markers.map((marker) =>
        extractTooltipMarkerProps(marker),
      );
    } else {
      const closeMarkerGroup = markers.map((marker) =>
        extractTooltipMarkerProps(marker),
      );

      closeMarkers.push(closeMarkerGroup);
    }
  });

  return {
    hoveredMarkers,
    closeMarkers,
  };
};
